## 防抖
> 事件被触发n秒后开始执行，如果n秒再次触发，则重新计时

#### 非立即执行版本
*在触发事件后函数 1 秒后才执行，而如果我在触发事件后的 1 秒内又触发了事件，则会重新计算函数执行时间。*
``` js
function debounce(func,wait){
	let timeout
	return funtion(){
		let context = this
		let args = argunments
		if(timeout) clearTimeout(timeout)
		timeout = setTimeout(()=>{
			func.apply(context,args)
		},wait)
	}
}
```
#### 立即执行版本
*触发事件后函数会立即执行，然后 n 秒内不触发事件才能继续执行函数的效果。*
``` js
function debounce(func,wait){
	let timeout
	return function(){
		let context = this
		let args = argunments
		if(timeout) clearTimeout(timeout)
		let callnow = !timeout
		timeout = setTimeout(()=>{
			timeout = null
		},wait)
		if(callnow) func.apply(context,args)
	}
}
```

## 节流
> 规定一个时间单位n秒,在n秒内连续多次触发事件，只能有一次执行

#### 时间戳版本
*在持续触发事件的过程中，函数会立即执行，并且每 1s 执行一次。*
``` js
function throttle(func,wait){
	let time = 0
	return function(){
		let context = this
		let args = argunments
		let now = Date.now()
		if(now - time > wait){
			func.apply(context,args)
			time = now
		}
	}
}
```

#### 定时器版本
*在持续触发事件的过程中，函数不会立即执行，并且每 1s 执行一次，在停止触发事件后，函数还会再执行一次。*
``` js
function throttle(func,wait){
	let timeout
	return function(){
		let context = this
		let args = argunments
		if(!timeout){
			timeout = setTimeout(()=>{
				timeout = null
				func.apply(func,args)
			},wait)
		}
	}
}
```
